// Helper function to get questions filtered by topic
export const getQuestionsByTopic = (topic) => {
  if (topic === "All") return topicsData;
  return topicsData.filter(q => q.topic === topic);
};

// Helper function to get questions filtered by pattern
export const getQuestionsByPattern = (pattern) => {
  if (pattern === "All") return topicsData;
  return topicsData.filter(q => q.pattern === pattern);
};

// Helper function to get all unique sources
export const getSources = () => {
  const sources = new Set();
  topicsData.forEach(q => {
    if (q.sources) {
      q.sources.split(', ').forEach(s => sources.add(s));
    }
  });
  return ["All", ...Array.from(sources).sort()];
};

// Helper function to get difficulty levels
export const difficulties = ["All", "Easy", "Medium", "Hard", "Very Hard"];

// Helper function to get total questions count
export const getTotalQuestions = () => topicsData.length;

// Helper function to get questions by difficulty
export const getQuestionsByDifficulty = (difficulty) => {
  if (difficulty === "All") return topicsData;
  return topicsData.filter(q => q.difficulty === difficulty);
};

// Helper function to search questions
export const searchQuestions = (searchTerm) => {
  const term = searchTerm.toLowerCase();
  return topicsData.filter(q => 
    q.name.toLowerCase().includes(term) ||
    q.topic.toLowerCase().includes(term) ||
    q.pattern.toLowerCase().includes(term) ||
    (q.sources && q.sources.toLowerCase().includes(term))
  );
};

export default topicsData;